# Auto-classify alert severity using the matrix
from dataclasses import dataclass
from enum import Enum

class Severity(Enum):
    SEV1 = 1
    SEV2 = 2
    SEV3 = 3
    SEV4 = 4

@dataclass
class IncidentSignals:
    error_rate: float            # 0.0 to 1.0
    affected_user_pct: float     # 0.0 to 1.0
    pii_exposed: bool
    irreversible_actions: bool
    complete_outage: bool
    hallucination_detected: bool
    financial_impact_usd: float

def classify_severity(signals: IncidentSignals) -> Severity:
    # SEV-1 conditions (any one triggers)
    if signals.pii_exposed:
        return Severity.SEV1
    if signals.irreversible_actions and signals.financial_impact_usd > 1000:
        return Severity.SEV1
    if signals.complete_outage and signals.affected_user_pct > 0.5:
        return Severity.SEV1

    # SEV-2 conditions
    if signals.error_rate > 0.20 or signals.affected_user_pct > 0.20:
        return Severity.SEV2
    if signals.hallucination_detected and signals.affected_user_pct > 0.05:
        return Severity.SEV2
    if signals.complete_outage:
        return Severity.SEV2

    # SEV-3 conditions
    if signals.error_rate > 0.01 or signals.affected_user_pct > 0.01:
        return Severity.SEV3

    return Severity.SEV4
